var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"어, 어엇……!? 마! 마! 그카지마라!","JPN":"え、ええっ……！？　ちょ！　ちょっと！　やめてや！","ENG":"H-huh...?! Hey! Don’t do that!","TWN":"喔，喔喔……！？喂！喂！不可以！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}},"sfx":"FX_COMBAT_ONLY_GAMECIRCLE_C_STAR_START"},{"id":"L5_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"작작해라 안 카나! 왜 자꾸 멀리서 장풍만 쏴제끼는데? 팍팍 온나!","JPN":"いい加減にせえや！　なんで遠くで弾撃ちまくってんの？　早く来いや！","ENG":"I’m tellin’ ya, quit it! All ya do is to throw them fireballs at me! Stop cowerin’ and come at me!","TWN":"你夠了唄！只敢躲遠遠的用掌風攻擊嗎？有種過來！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"헤헷, 원래 샐러리맨X는 견제기 위주로 플레이 하다가 과장 펀치 한 방을 노리는 캐릭터라고요!","JPN":"へへっ、もともとサラリーマンXは牽制技を中心にプレイして、課長パンチ一発を狙うキャラなんですよ！","ENG":"Heh, you forgot the fact that Salaryman X is a chance seeker!","TWN":"嘿嘿，上班族X本來主要就是用牽制技，然後才會伺機使用科長拳的角色！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"엇! 지금이다! 만성! 피로권……! 하아아아앗!!","JPN":"あっ！　今だ！　慢性！　疲労拳……！　はああああっ！！","ENG":"Ah, now’s the perfect timing! Burnout! Fist! Haaahhh!","TWN":"喔！就是現在！慢性！疲勞拳……！看我的厲害害害！！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아 쫌! 윽수로 얍삽하네! 니 소인배가?","JPN":"ちょっと！　めっちゃズルいやん！　あんた、クズなん？","ENG":"Oh, come on! That was a cheap shot! A sucker punch!","TWN":"可惡！好奸詐！你這個狡猾的小人！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"소, 소인배?","JPN":"く、クズ？","ENG":"S-sucker punch?!","TWN":"狡…狡猾的小人"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쯧쯔…… 그라믄 안 돼 그라믄.","JPN":"ちっちっ……そんなんあかん、そんなん。","ENG":"Tsk tsk... That ain’t right.","TWN":"嘖嘖，不可以這樣唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐든 그렇게 쫌생이처럼 하믄…… 니 나중에 머리털 다 빠져서 대머리 된다?","JPN":"何でもそうズルくしたら……あんた、後で髪の毛全部抜けてハゲるで？","ENG":"If ya keep doing things in that cowardly manner... All your hair will fall out, and you’ll go bald!","TWN":"你再這麼狡猾的話……當心你以後頭髮會掉光變成禿頭喔！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"무슨 소리에요! 저 머리 숱 엄청 많거든요!","JPN":"何言ってるんですか！　僕、髪の毛はいっぱいありますから！","ENG":"What are you talking about?! I have thick, luscious hair!","TWN":"你胡說！我的頭髮多得咧！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L16_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 그럼 그 상자 대가리 한 번 벗어보든가!","JPN":"へへっ、じゃあその箱、一度取ってみよか！","ENG":"Heh, then why don’t ya take off that cardboard mask right now?","TWN":"嘿嘿，有本事你就把紙箱拿下來看看唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"N-no...","TWN":"我…我…"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"앗!? 그런기가? 혹시 벌써부터 머리카락이 없는 거 아이가? 그럼 미안하데이~","JPN":"あっ！？　あれか？　もしかしてもう髪の毛ないんちゃう？　それやったらごめんな～","ENG":"Ah? Is that it?! Ya ain’t got no hair! Whoops!","TWN":"難道！？其實你現在就已經禿啦？真抱歉戳到你的痛處～"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 아니라니까요! 제가 이 마스크를 계속 쓰고 있는 이유는……","JPN":"ち、違いますってば！　僕がこのマスクをずっと被ってる理由は……","ENG":"I-I do have hair! The reason why I keep this mask on is–","TWN":"才…才沒有！我會一直戴著這個紙箱是因為……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하아아아앗! 빈틈이다! 간데이! 어퍼커어어엇!!","JPN":"はああああっ！　隙あり！　行くで！　アッパーカ～ット！！","ENG":"Hyaaaah! An opening! Here I come! Uppercut!","TWN":"啊啊啊啊！有機會！看我的！上鉤拳拳拳拳！！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오예! 내 승리다! 니 잘한다카더만 별것도 아니네!","JPN":"イェーイ！　ウチの勝利！　あんた、ウマいって言うてたけど大したことないねんな！","ENG":"Alrighty! Victory! You ain’t got much to boast over, weakling!","TWN":"Oh yeah！我贏了！在那邊說得好像多厲害，不過如此而已唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"박스! 내를 이기고 싶음 30년은 더 수련하도록!","JPN":"ダンボール！　ウチに勝ちたいんやったら30年修行してこい！","ENG":"Box! It’s gonna take another 30 years for ya to beat me!","TWN":"紙箱！想贏過我回家練個30年再來唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"머리카락 다 벗겨질 때까지 말이제! 와하하핫……!!","JPN":"ハゲになるまでな！　ガハハハッ……！！","ENG":"Until ya go fully bald! Ah ha ha ha...!","TWN":"練到你頭髮掉光為止！哇哈哈哈……！！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"으으, 계속 지다가 겨우 딱 한 판 이긴 거 가지고……!","JPN":"うう、ずっと負けてて、やっと一度勝ったくせに……！","ENG":"Ugh, you won one round out of a hundred defeats...!","TWN":"可惡，前面都是你輸，不過才贏一場而已，在那邊……！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"인정 못해요! 한 판 더 해요!","JPN":"認めません！　もう一回やりましょう！","ENG":"I won’t accept it! Let’s play again!","TWN":"我不承認！再來一局！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헤, 싫다~ 내는 허접이랑 안 놀랜다~","JPN":"へへ、イヤやな～ウチは下手くそとは遊ばれへんわ～","ENG":"Heh, no can do! I don’t play with noobs, ya see.","TWN":"嘿嘿，才不要～你那麼弱，我才不想和你打咧～"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"으으……! 그때, <color=#ffd34c>필살기</color>만 제대로 들어갔으면 내가 이기는 건데!","JPN":"うう……！　あの時、<color=#ffd34c>必殺技</color>さえちゃんと当たったら僕の勝ちだったのに！","ENG":"Gaahhh...! If only my <color=#ffd34c>special move</color> hit properly...!","TWN":"可惡……！那時候有順利使出<color=#ffd34c>必殺技</color>的話，贏的就是我！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으음……?","JPN":"ううん……？","ENG":"Hmm…?","TWN":"嗯……？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아아아아아아아아아앗……!? 그래! 그거다! 내 필살기……!!","JPN":"ああああああああああっ……！？　そう！　それや！　ウチの必殺技……！！","ENG":"AAAAAAH...?! Yeah, that’s it! My special move...!","TWN":"啊啊啊啊啊啊啊啊……！？沒錯！就是那個！我的必殺技……！！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L35_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 다들 잘 보래이!","JPN":"へへっ、みんな、よく見いや！","ENG":"Heh. Attention, folks!","TWN":"嘿嘿，你們看好喔！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"처음에 이래 삼색 속성을 전부 다룰 수 있는 마스터 소드를 뽑아가……","JPN":"最初は、こうやって三色属性を全部扱えるマスターソードを抜いて……","ENG":"So, I yield a master sword that controls all three elements...","TWN":"一開始先拔出可以控制三種屬性的大師寶劍……"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"슉슉……! 빠르게 적에 간격에 들어가, 파바바바밧 하고 연속으로 참격을 날리는거지!","JPN":"すぱぱっ……！　早く敵陣に入って、ドドドドドッって連続で斬撃を飛ばすんや！","ENG":"Wham! I dash into the enemy line, then slash slash slash! I slit them, fast and furious!","TWN":"咻咻……！然後再衝到敵人陣營裡，啪啪啪啪之後，就會出現連續斬擊！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그라믄…… 세 속성의 이팩트를 스까서 퍼버버버벙! 하고 폭발하는 느낌인기다!","JPN":"そしたら……三属性のエフェクトを混ぜてクガガガガっ！って爆発する感じやで！","ENG":"It’ll be like all three elements explodin’ at the same time! B-b-boom!","TWN":"這樣……三種屬性的效果就會砰砰砰砰！爆炸，這樣！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷! 어때! 박스? 이제 내 말 알아듣겠제?","JPN":"へへっ！　どうや！　ダンボール！　これでウチの言うこと、わかったやろ？","ENG":"Heh! How ya like that? Ya get what I’m sayin’?","TWN":"嘿嘿！怎麼樣？紙箱你聽得懂我在說什麼嗎？"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아니, 그러니까 <color=#ffd34c>슉슉!, 파바바바밧!, 퍼버버버벙!</color>하는 게 어떤 느낌인데요?","JPN":"え、つまり<color=#ffd34c>すぱぱっ！　ドドドドドッ！　クガガガガッ！</color>ってどんな感じなんですか？","ENG":"No, what the heck are these <color=#ffd34c>wham, slash slash slash, b-b-boom</color> even supposed to mean?","TWN":"聽不懂，什麼<color=#ffd34c>咻咻！啪啪啪啪！砰砰砰砰！</color>這是什麼？"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그니까! 이래 슉슉! 검을 베믄 파바바밧! 하고 퍼버버버벙! 터진다고! 와 이해를 못하노!","JPN":"だから！　こうやってすぱぱっ！って剣で斬ると、ドドドドドッ！ってなって、クガガガガっ！って爆発するんや！　なんでわからへんの！？","ENG":"It means that I go wham, then go slash with my sword and everything blows up, boom boom boom! It ain't hard! So simple!","TWN":"就是！就是像這樣咻咻！用劍砍，然後啪啪啪啪！再砰砰砰砰！有這麼難嗎！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나들! 누나들은 저게 무슨 뜻인지 알겠어요? 제가 이상한 거예요?","JPN":"みなさん！　みなさんはあれがどういう意味なのかわかるんですか？　僕がおかしいんですか？","ENG":"Um! Is anyone following her? Tell me I’m not the only one who doesn’t get it.","TWN":"各位姊姊！你們聽得懂她在說什麼嗎？是我的問題嗎？"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……츄르릅. 츄릅","JPN":"……ちゅー。ズズ。","ENG":"...*Slurp*","TWN":"……嚕嚕嚕。"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"흠~ 흠~ 역시 여기서는 귀여운 역관절을 넣어볼까나?","JPN":"ふ～ん、ふふん、やっぱりここにはかわいい逆関節を入れてみようかな？","ENG":"*Humming* A bit of reversed joints will do the trick here!","TWN":"嗯～嗯～這裡果然該放個像貞子那樣的可愛怪物比較好嗎？"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아니면 이번에는 절지 동물에서…….","JPN":"それとも、今度は節足動物から……","ENG":"Or maybe an arthropod-like design...","TWN":"還是要節肢動物……"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이 누나들이……!","JPN":"この人たち……！","ENG":"Seriously?!","TWN":"你們……！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"게임은 함께 만드는 거라고 그럴 땐 언제고, 왜 이럴 때는 다들 외면하는 건데요!","JPN":"ゲームは一緒に作ると言っておきながら、なんでこういう時には聞いてないふりするんですか！","ENG":"Wasn’t this all about being a team? Why are you all ignoring me?!","TWN":"還說什麼要一起做遊戲，結果現在無視我是怎樣！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"안 되겠어! 누나, 그냥 멋있게 그리기만 하면 되는 거죠?","JPN":"もういいです！　マリさん、ただカッコよく描けばいいんですよね？","ENG":"Whatever! Rinae, you just need your stuff to look cool, right?","TWN":"聽不懂啦！反正就是要畫得很酷對吧？"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L8_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그냥 제가 멋있는 검술로 몇 개 골라볼 테니까. 그 중에 하나 골라보세요!","JPN":"僕がカッコいい剣術を何個かピックアップするので、その中から一つ選んでください！","ENG":"I’ll come up with some flashy moves. Pick one!","TWN":"我會挑幾個劍術，你再從中選你想要的吧！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그럼 적당히 비슷하게 그려볼 테니까.","JPN":"それに合わせて適当に似せて描いてみますから。","ENG":"Then I’ll try to copy the motion in reasonable quality.","TWN":"我再畫得差不多就好！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐라고!? 적당히? 니 지금 적당히라 그랬나?","JPN":"何！？　適当に？！　あんた、今適当って言うた？","ENG":"Ah? Reasonable? Did ya say reasonable?","TWN":"你說啥！？差不多？你說差不多就好？"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내 원래 평범한 건 딱 질색이다. 그런 시시한 필살기는 거절한데이!","JPN":"ウチは平凡なのは大っ嫌いなんや。そんなくだらない必殺技はお断りするわ！","ENG":"I ain’t so keen on the usual stuff. A typical special move? B-o-r-i-n-g!","TWN":"我的字典裡沒有差不多，我不需要那種無聊的必殺技！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>미리네★스타라이트 스페샬</color>에 적당히는 없다 이 말이제!","JPN":"<color=#ffd34c>マリ★スターライトスペシャル</color>に適当なんてありえへん！","ENG":"There’s no ordinary in<color=#ffd34c>Mi Rinae★Starlight Special</color>!","TWN":"<color=#ffd34c>宓璃奈★星光特技</color>不能差不多！"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"벌써 이름까지 지었어요……?","JPN":"もう名前までつけてるんですか……？","ENG":"You already have a name for it, huh...?","TWN":"你連名字都取好啦……？"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하아, 이 사람 대체 얼마나 진심인 거야…….","JPN":"はあ、この人、どれだけ本気なんだ……","ENG":"*Sigh...* How devoted is this person, really...?","TWN":"哀，她是認真的嗎……"},"stage":{"bg":"GAMECIRCLE_05","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으음, 리네야. 그럼 코미페에서 했던 것처럼 네가 직접 필살기를 보여주는 게 어떨까?","JPN":"うーん。じゃあ、コミフェでやってたみたいに、実際にマリちゃんが必殺技を見せてあげるのはどう？","ENG":"Hmm... Then why don’t you try demonstrating, Rinae? Like when you posed for us back at Comic Fest.","TWN":"那這樣吧，璃奈，你就親自示範一下必殺技吧？像上次在動漫展那樣。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼, 내가 사진을 찍고…… 박스 군은 그걸 그리고…… 보라는 그걸 구현하는 거지.","JPN":"で、私が写真を撮って……ダンボール君はそれを描いて……シホはそれを具現化するの。","ENG":"I’ll take the pictures... Boxie will sketch out the poses... then Bora will model it.","TWN":"我負責拍下來……紙箱小朋友負責畫出來……然後寶拉負責放到遊戲裡。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 생각만 해도 너무 귀여울 것 같아!","JPN":"ふふっ、想像しただけでもとてもかわいい！","ENG":"Heh heh, it’s going to be super cute!","TWN":"呵呵，光想就覺得很可愛欸！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오호 그거 좋은데!?","JPN":"ほほぉ、それええな！？","ENG":"Alrighty! Sounds good!","TWN":"喔呵，不錯喔！？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아니, 아니 잠깐만요! 미리네 누나가 아무리 운동 신경이 좋다고 해도…….","JPN":"いや、いやちょっと待ってください！　マリさんの運動神経がいくら良くても……","ENG":"W-wait! I know you're an athlete, but...","TWN":"真的假的，我沒聽錯吧！就算宓璃奈姊姊的運動神經再好……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"지금 만화에서나 나올 것 같은 필살기를 실제로 보여주겠다고요?","JPN":"今ここで、漫画に出てくるような必殺技を実際に見せることなんてできるんですか？","ENG":"You can’t pull of moves that only exist in comic books!","TWN":"但現在是要親自示範像漫畫那種必殺技嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐라고? 내 못할 거 같나? 내는 자신있다!","JPN":"何やて？　ウチができないと思うんか？　ウチは自信あるんやで！","ENG":"Ya doubtin’ me, kiddo? Ain’t nothin’ stoppin’ me!","TWN":"怎樣？你覺得我不行嗎？我可是很有信心！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아니! 이건 자신감의 문제가 아니잖아요!","JPN":"ええっ！？　これは自信があるかどうかの問題じゃないですよ！","ENG":"This isn’t a problem of self-motivation!","TWN":"不是有沒有信心的問題啦！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"좋네! 그럼 결정이다! 박스, 니 딱 기다리래이!","JPN":"ええな！　じゃあ、決まりや！　ダンボール、待ってろよ！","ENG":"Good! I guess we’re all settled, then? You just wait, Box!","TWN":"好！我決定了！紙箱，你等著看唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내 지금부터 쪼매 훈련해가 미리네★스타라이트 스페샬…… 완벽하게 보여줄 테니까!","JPN":"ウチ、今からちっと訓練して、マリ★スターライトスペシャル……完璧に見せたるから！","ENG":"I’ll show you the ultimate Mi Rinae★Starlight Special in no time...!","TWN":"我現在就去練習，等我把宓璃奈★星光特技練好後……再示範給你看！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……하아. 그러니까 이게 훈련의 문제인 거냐고…….","JPN":"……はあ。だから、これは訓練の問題じゃないって……","ENG":"*Sigh...* She’s not getting it, is she...?","TWN":"……哀，就說不是練習的問題嘛……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};